import{_ as o,o as a,c as l,ae as c}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"헬스 체크","description":"헬스 체크 명령 및 게이트웨이 헬스 모니터링","frontmatter":{"title":"헬스 체크","description":"헬스 체크 명령 및 게이트웨이 헬스 모니터링"},"headers":[],"relativePath":"gateway/health.md","filePath":"gateway/health.md","lastUpdated":null}'),t={name:"gateway/health.md"};function d(i,e,n,s,h,r){return a(),l("div",null,[...e[0]||(e[0]=[c('<h1 id="헬스-체크-cli" tabindex="-1">헬스 체크 (CLI) <a class="header-anchor" href="#헬스-체크-cli" aria-label="Permalink to &quot;헬스 체크 (CLI)&quot;">​</a></h1><p>추측 없이 채널 연결을 확인하기 위한 간단한 가이드입니다.</p><h2 id="빠른-체크" tabindex="-1">빠른 체크 <a class="header-anchor" href="#빠른-체크" aria-label="Permalink to &quot;빠른 체크&quot;">​</a></h2><ul><li><code>openclaw status</code> — 로컬 요약: 게이트웨이 연결 가능성/모드, 업데이트 힌트, 연결된 채널 인증 나이, 세션 + 최근 활동.</li><li><code>openclaw status --all</code> — 전체 로컬 진단 (읽기 전용, 색상, 디버깅을 위해 붙여넣기 안전).</li><li><code>openclaw status --deep</code> — 실행 중인 게이트웨이에 라이브 헬스 프로브(<code>probe:true</code>를 포함한 <code>health</code>)를 요청합니다. 지원되는 경우 계정별 채널 프로브 포함.</li><li><code>openclaw health</code> — 실행 중인 게이트웨이에 헬스 스냅샷을 요청합니다 (WS 전용; CLI에서 직접 채널 소켓 없음).</li><li><code>openclaw health --verbose</code> — 라이브 헬스 프로브를 강제하고 게이트웨이 연결 세부 사항을 인쇄합니다.</li><li><code>openclaw health --json</code> — 기계 가독 헬스 스냅샷 출력.</li><li>에이전트를 호출하지 않고 상태 응답을 받으려면 WhatsApp/WebChat에서 <code>/status</code>를 독립 메시지로 전송합니다.</li><li>로그: <code>/tmp/openclaw/openclaw-*.log</code>를 tail하고 <code>web-heartbeat</code>, <code>web-reconnect</code>, <code>web-auto-reply</code>, <code>web-inbound</code>를 필터링합니다.</li></ul><h2 id="심층-진단" tabindex="-1">심층 진단 <a class="header-anchor" href="#심층-진단" aria-label="Permalink to &quot;심층 진단&quot;">​</a></h2><ul><li>디스크의 자격 증명: <code>ls -l ~/.openclaw/credentials/whatsapp/&amp;lt;accountId&amp;gt;/creds.json</code> (mtime이 최근이어야 함).</li><li>세션 스토어: <code>ls -l ~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/sessions.json</code>. 수 및 최근 수신자는 <code>status</code>를 통해 표면화됩니다.</li><li>재연결 흐름: 로그에 상태 코드 409–515 또는 <code>loggedOut</code>이 나타날 때 <code>openclaw channels logout &amp;&amp; openclaw channels login --verbose</code>. (참고: QR 로그인 흐름은 페어링 후 상태 515에 대해 한 번 자동 재시작됩니다.)</li></ul><h2 id="헬스-모니터-구성" tabindex="-1">헬스 모니터 구성 <a class="header-anchor" href="#헬스-모니터-구성" aria-label="Permalink to &quot;헬스 모니터 구성&quot;">​</a></h2><ul><li><code>gateway.channelHealthCheckMinutes</code>: 게이트웨이가 채널 헬스를 체크하는 빈도. 기본값: <code>5</code>. 전역적으로 헬스 모니터 재시작을 비활성화하려면 <code>0</code>으로 설정.</li><li><code>gateway.channelStaleEventThresholdMinutes</code>: 연결된 채널이 헬스 모니터가 오래된 것으로 처리하고 재시작하기 전에 유휴 상태를 유지할 수 있는 기간. 기본값: <code>30</code>. <code>gateway.channelHealthCheckMinutes</code> 이상으로 유지하십시오.</li><li><code>gateway.channelMaxRestartsPerHour</code>: 채널/계정별 헬스 모니터 재시작에 대한 롤링 1시간 상한. 기본값: <code>10</code>.</li><li><code>channels.&amp;lt;provider&amp;gt;.healthMonitor.enabled</code>: 전역 모니터링을 활성화한 상태에서 특정 채널에 대한 헬스 모니터 재시작 비활성화.</li><li><code>channels.&amp;lt;provider&amp;gt;.accounts.&amp;lt;accountId&amp;gt;.healthMonitor.enabled</code>: 채널 수준 설정보다 우선하는 멀티 계정 재정의.</li><li>이러한 채널별 재정의는 오늘날 이를 노출하는 내장 채널 모니터에 적용됩니다: Discord, Google Chat, iMessage, Microsoft Teams, Signal, Slack, Telegram, WhatsApp.</li></ul><h2 id="문제-발생-시" tabindex="-1">문제 발생 시 <a class="header-anchor" href="#문제-발생-시" aria-label="Permalink to &quot;문제 발생 시&quot;">​</a></h2><ul><li><code>logged out</code> 또는 상태 409–515 → <code>openclaw channels logout</code> 후 <code>openclaw channels login</code>으로 재연결.</li><li>게이트웨이 연결 불가 → 시작: <code>openclaw gateway --port 18789</code> (포트가 사용 중이면 <code>--force</code> 사용).</li><li>인바운드 메시지 없음 → 연결된 전화기가 온라인 상태이고 발신자가 허용되는지 확인 (<code>channels.whatsapp.allowFrom</code>); 그룹 채팅의 경우 허용 목록 + 언급 규칙이 일치하는지 확인 (<code>channels.whatsapp.groups</code>, <code>agents.list[].groupChat.mentionPatterns</code>).</li></ul><h2 id="전용-health-명령" tabindex="-1">전용 &quot;health&quot; 명령 <a class="header-anchor" href="#전용-health-명령" aria-label="Permalink to &quot;전용 &quot;health&quot; 명령&quot;">​</a></h2><p><code>openclaw health</code>는 실행 중인 게이트웨이에 헬스 스냅샷을 요청합니다 (CLI에서 직접 채널 소켓 없음). 기본적으로 신선한 캐시된 게이트웨이 스냅샷을 반환할 수 있습니다; 그런 다음 게이트웨이는 백그라운드에서 해당 캐시를 새로 고칩니다. <code>openclaw health --verbose</code>는 라이브 프로브를 강제합니다. 이 명령은 연결된 자격 증명/인증 나이, 채널별 프로브 요약, 세션 스토어 요약, 프로브 기간을 보고합니다. 게이트웨이에 연결할 수 없거나 프로브가 실패/타임아웃되면 0이 아닌 값으로 종료됩니다.</p><p>옵션:</p><ul><li><code>--json</code>: 기계 가독 JSON 출력</li><li><code>--timeout &amp;lt;ms&amp;gt;</code>: 기본 10초 프로브 타임아웃 재정의</li><li><code>--verbose</code>: 라이브 프로브를 강제하고 게이트웨이 연결 세부 사항 인쇄</li><li><code>--debug</code>: <code>--verbose</code>의 별칭</li></ul><p>헬스 스냅샷에는 <code>ok</code> (불리언), <code>ts</code> (타임스탬프), <code>durationMs</code> (프로브 시간), 채널별 상태, 에이전트 가용성, 세션 스토어 요약이 포함됩니다.</p>',15)])])}const m=o(t,[["render",d]]);export{u as __pageData,m as default};
